import{_ as t,o,c as s,a2 as a}from"./chunks/framework.CKCxdkvf.js";const g=JSON.parse('{"title":"RFC-016 — Spaceflight Fleet · architecture, schema, and dataset boundaries","description":"","frontmatter":{},"headers":[],"relativePath":"rfc/RFC-016.md","filePath":"rfc/RFC-016.md"}'),i={name:"rfc/RFC-016.md"};function r(n,e,d,c,l,h){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="rfc-016-—-spaceflight-fleet-·-architecture-schema-and-dataset-boundaries" tabindex="-1">RFC-016 — Spaceflight Fleet · architecture, schema, and dataset boundaries <a class="header-anchor" href="#rfc-016-—-spaceflight-fleet-·-architecture-schema-and-dataset-boundaries" aria-label="Permalink to &quot;RFC-016 — Spaceflight Fleet · architecture, schema, and dataset boundaries&quot;">​</a></h1><p><em>Orrery · Open RFC · v0.1 · May 2026</em></p><blockquote><p><strong>Status:</strong> Draft <strong>Author:</strong> product <strong>Closes into:</strong> ADR-052 (fleet schema + cross-reference contract), ADR-053 (mission badge + crew portrait sourcing), ADR-054 (fleet i18n strategy) <strong>Slice gate:</strong> v0.6 <strong>Why this is an RFC:</strong> PRD-012 promises a curated 50-entry inventory of the machines used in spaceflight — launchers, crewed spacecraft, cargo spacecraft, stations, rovers, landers, orbiters, observatories — each cross-linked to the existing <code>missions.json</code> / <code>iss-*</code> / <code>tiangong-*</code> / <code>earth-objects</code> data. The technical questions cluster three ways: <em>schema</em> (one canonical entry per hardware family, but the existing datasets already carry overlapping fields — what&#39;s source-of-truth and what&#39;s reference?), <em>imagery + crew badges</em> (mission patches and crew portraits are the V1 lock-in differentiator from <code>/missions</code>, and they need their own provenance discipline), and <em>i18n + scope discipline</em> (50 entries × 14 locales = 700 overlay files; we already have a working pipeline from Tiangong but the entries are heterogeneous categories with different editorial templates).</p></blockquote><hr><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Orrery has six hardware datasets today:</p><table tabindex="0"><thead><tr><th>Dataset</th><th>Path</th><th>Records</th><th>Purpose</th></tr></thead><tbody><tr><td><code>rockets.json</code></td><td><code>static/data/rockets.json</code></td><td>13</td><td>Launcher specs (used by <code>/missions</code> and <code>/plan</code>)</td></tr><tr><td><code>iss-modules</code> + <code>iss-visitors</code></td><td><code>static/data/iss-*.json</code> + i18n</td><td>18 + 7</td><td>Pressurised modules + visiting fleet</td></tr><tr><td><code>tiangong-modules</code> + <code>tiangong-visitors</code></td><td><code>static/data/tiangong-*.json</code> + i18n</td><td>3 + 2</td><td>Mirror of the ISS shape</td></tr><tr><td><code>moon-sites.json</code></td><td><code>static/data/moon-sites.json</code></td><td>~20</td><td>Lunar landing sites (rover + lander as <code>payload</code> strings, not first-class)</td></tr><tr><td><code>mars-sites.json</code></td><td><code>static/data/mars-sites.json</code></td><td>~12</td><td>Mars landing sites (similar shape to moon-sites)</td></tr><tr><td><code>earth-objects.json</code></td><td><code>static/data/earth-objects.json</code></td><td>~30</td><td>LEO satellites (Hubble, JWST currently live here as orbital objects)</td></tr></tbody></table><p>Today, &quot;what hardware exists&quot; is fragmented across these six files plus the 36 <code>missions/*</code> records. A user looking for <em>Saturn V</em> finds the launcher in <code>rockets.json</code> and the missions it launched in <code>missions/</code>. A user looking for <em>Curiosity</em> finds the rover encoded as a <code>payload: &quot;Curiosity&quot;</code> string on a Mars site, with no first-class entry. A user looking for <em>Hubble</em> finds it as an <code>earth-objects</code> orbital object. Nothing today gives the unified hardware-inventory view PRD-012 asks for.</p><p>The simplest aggregator is a new <code>fleet.json</code> (with locale overlays) that becomes <em>the canonical hardware-family entry</em> and references the existing data via cross-link IDs. The existing datasets remain authoritative for their scoped purpose — <code>rockets.json</code> keeps its launcher specs that <code>/plan</code> reads at runtime; <code>iss-modules</code> keeps its station-specific module attributes that <code>/iss</code> reads. Fleet entries copy what they need into a flatter schema for the fleet-card grid + detail panel.</p><p>PRD-012&#39;s V1 lock: <strong>50 curated entries</strong>, <strong>crew + badges in V1</strong>, route at <strong>/fleet</strong> between MARS and SCIENCE in the nav.</p><hr><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><h3 id="oq-1-—-one-unified-fleet-json-vs-per-category-files" tabindex="-1">OQ-1 — One unified <code>fleet.json</code> vs per-category files? <a class="header-anchor" href="#oq-1-—-one-unified-fleet-json-vs-per-category-files" aria-label="Permalink to &quot;OQ-1 — One unified `fleet.json` vs per-category files?&quot;">​</a></h3><p>PRD-012 lists 8 categories. Two structural options:</p><table tabindex="0"><thead><tr><th>Option</th><th>Layout</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>A. Single <code>fleet.json</code></strong> with all 50 entries</td><td>One ~2,000-line file mirroring <code>missions/index.json</code></td><td>Easiest to validate, easiest to filter (single load), matches <code>/missions</code> precedent</td><td>Heterogeneous schema fields per category creep into one document</td></tr><tr><td><strong>B. Per-category files</strong> under <code>static/data/fleet/{category}/{id}.json</code> + <code>fleet/index.json</code></td><td>Mirrors the existing <code>missions/{dest}/{id}.json</code> pattern</td><td>Lets per-category schema variation breathe; smaller files</td><td>More fetches, more validation surface</td></tr><tr><td><strong>C. Single index + per-entry detail</strong> like <code>missions/index.json</code> + <code>missions/mars/curiosity.json</code></td><td>Index has summary fields; detail file has full record</td><td>Lazy-loadable, scales to V2 (~150 entries)</td><td>More files than A, more plumbing than A</td></tr></tbody></table><p><strong>Recommendation: C</strong> — mirror the proven <code>/missions</code> pattern. <code>static/data/fleet/index.json</code> carries the 50-entry summary (id, name, category, agency, era, first-flight year, status, hero-image path, tagline). <code>static/data/fleet/{category}/{id}.json</code> carries the per-entry detail (specs, linked_missions, links, gallery manifest, crew). Locale overlays live at <code>static/data/i18n/{locale}/fleet/{category}/{id}.json</code> — same shape as <code>missions</code>. The category-keyed directory makes new entries discoverable by humans editing the repo.</p><p>This locks into ADR-052 alongside the cross-reference contract.</p><hr><h3 id="oq-2-—-cross-reference-contract-how-do-fleet-entries-link-to-missions" tabindex="-1">OQ-2 — Cross-reference contract: how do fleet entries link to missions? <a class="header-anchor" href="#oq-2-—-cross-reference-contract-how-do-fleet-entries-link-to-missions" aria-label="Permalink to &quot;OQ-2 — Cross-reference contract: how do fleet entries link to missions?&quot;">​</a></h3><p>A Saturn V fleet entry needs to surface the 13 Apollo + Skylab missions it launched. The MISSIONS tab in the detail panel (PRD-012 §what-it-must-do) reads these from the fleet record and renders them as mini-cards linking to <code>/missions?id={mission_id}</code>.</p><table tabindex="0"><thead><tr><th>Option</th><th>Direction</th><th>Field shape</th><th>Build-time check</th></tr></thead><tbody><tr><td><strong>A. Fleet → missions only</strong> (one-way)</td><td><code>fleet[*].linked_missions: [&#39;apollo11&#39;, ...]</code></td><td>Simple array of mission IDs on each fleet entry</td><td><code>validate-data.ts</code> asserts every linked_missions ID exists in <code>missions/index.json</code></td></tr><tr><td><strong>B. Bidirectional</strong></td><td>Plus <code>missions[*].launch_vehicle: &#39;saturn-v&#39;</code> already exists today, just formalise the join</td><td>Fleet panel reads its own list; missions panel can render &quot;see also: Saturn V&quot; link</td><td>Symmetric assertion at build</td></tr><tr><td><strong>C. Auto-derived from missions</strong></td><td>Fleet&#39;s MISSIONS list is computed from <code>missions[*].launch_vehicle === fleet_id</code></td><td>Zero hand-curation; always in sync</td><td>Less control over ordering / categorisation</td></tr></tbody></table><p><strong>Recommendation: A for V1, with C as a build-time augmentation.</strong> Fleet entries carry <code>linked_missions: [...]</code> for explicit curation control (e.g., a non-launcher entry like <em>Curiosity</em> needs to point to <code>mars2012</code>/MSL with no launch_vehicle relationship). At build time, <code>scripts/validate-data.ts</code> cross-checks: any <code>missions[*].launch_vehicle</code> that points to a fleet ID must appear in that fleet entry&#39;s <code>linked_missions</code> (catches drift), and any non-existent ID fails the build. The bidirectional reverse-link rendering (&quot;see also: Saturn V&quot; on the Apollo 11 mission panel) is deferred to V1.5 — clean V1 first.</p><p>This locks into ADR-052.</p><hr><h3 id="oq-3-—-mission-badges-crew-portraits-where-do-they-come-from" tabindex="-1">OQ-3 — Mission badges + crew portraits: where do they come from? <a class="header-anchor" href="#oq-3-—-mission-badges-crew-portraits-where-do-they-come-from" aria-label="Permalink to &quot;OQ-3 — Mission badges + crew portraits: where do they come from?&quot;">​</a></h3><p>PRD-012 V1 includes crew badges + crew portraits for crewed-spacecraft entries. Concrete sourcing:</p><table tabindex="0"><thead><tr><th>Asset</th><th>Source</th><th>Example</th><th>License</th></tr></thead><tbody><tr><td><strong>Mission patches</strong></td><td>Wikimedia Commons (NASA-released originals are PD-USGov; some Roscosmos / CNSA require careful vetting)</td><td>Apollo 11 patch, STS-1 patch, Demo-2 patch</td><td>PD-NASA / Roscosmos-released / CNSA-released</td></tr><tr><td><strong>Crew portraits</strong></td><td>Agency archives (NASA Image Library, ESA Photo Library, JAXA Library, Roscosmos), mirrored via Wikimedia Commons where available</td><td>Yuri Gagarin (Roscosmos archive), Neil Armstrong (NASA), Liu Yang (CMSA)</td><td>PD-USGov for NASA / fair-use risk for non-Western agencies</td></tr></tbody></table><p>The license-vetting pattern is exactly the existing pipeline (ADR-046 / ADR-047): every image gets a row in <code>static/data/image-provenance.json</code>, every license short-name appears in <code>scripts/license-allowlist.ts</code> or in <code>static/data/license-waivers.json</code>, the build fails closed if anything is unattributed.</p><p><strong>Sourcing approach:</strong></p><table tabindex="0"><thead><tr><th>Option</th><th>How</th><th>Trade-off</th></tr></thead><tbody><tr><td><strong>A. Wikimedia-only</strong></td><td>Fetch all imagery via the existing Wikimedia Commons fetch script</td><td>Easiest license vetting; some images may not be on Commons</td></tr><tr><td><strong>B. Agency-first (per ADR-046) with Wikimedia fallback</strong></td><td>Crew portraits prefer agency archives; patches prefer Wikimedia (since patches are typically uploaded there in canonical form)</td><td>Matches imagery-sourcing ADR-046 exactly; one extra agency-API integration per agency</td></tr><tr><td><strong>C. Hand-curated + manual upload to <code>static/images/fleet/</code></strong></td><td>Author selects each image, downloads, attributes, commits</td><td>Most editorial control; most authoring effort</td></tr></tbody></table><p><strong>Recommendation: B</strong> — extend the existing <code>scripts/fetch-assets.ts</code> with a fleet-imagery branch that mirrors the agency-first priority from ADR-046. Crew portraits route through agency archives first (NASA Image Library is well-documented with stable URLs; ESA / JAXA have similar APIs). Patches route through Wikimedia Commons (where official patches are uploaded in canonical form, which is the convention agencies themselves rely on). Failure to find an image at agency/Commons → entry can ship without that image (graceful no-op in the CREW tab, not a build-failure).</p><p>This locks into ADR-053.</p><hr><h3 id="oq-4-—-detail-panel-reuse-vs-new-component" tabindex="-1">OQ-4 — Detail panel reuse vs new component? <a class="header-anchor" href="#oq-4-—-detail-panel-reuse-vs-new-component" aria-label="Permalink to &quot;OQ-4 — Detail panel reuse vs new component?&quot;">​</a></h3><p>PRD-012 §what-it-must-do specifies tabs OVERVIEW / GALLERY / ANATOMY / CREW / MISSIONS / LEARN. The existing <code>StationModulePanel.svelte</code> carries OVERVIEW / GALLERY / ANATOMY / LEARN already. Two new tabs (CREW, MISSIONS) need to be added.</p><table tabindex="0"><thead><tr><th>Option</th><th>Implementation</th></tr></thead><tbody><tr><td><strong>A. Extend <code>StationModulePanel.svelte</code></strong> with conditional CREW + MISSIONS tabs</td><td>Single component, props gate which tabs render. Reuse all existing styling + tab nav</td></tr><tr><td><strong>B. New <code>FleetEntryPanel.svelte</code></strong> copy-pasted from <code>StationModulePanel</code></td><td>Cleaner separation; no risk of breaking <code>/iss</code> or <code>/tiangong</code></td></tr><tr><td><strong>C. Generic <code>EntityDetailPanel.svelte</code></strong> that both stations and fleet use</td><td>Refactor towards a unified component</td></tr></tbody></table><p><strong>Recommendation: B for V1, C as a refactor in v0.7.</strong> Copy <code>StationModulePanel.svelte</code> to <code>FleetEntryPanel.svelte</code> and add the two new tabs. The two existing station panels carry station-specific concerns (microgravity-axes integration, station context links) that don&#39;t apply to a Saturn V fleet entry; cleaner separation now, generalise later when the third use case proves the pattern. A small style-token extraction can land alongside (drawer chrome, tab nav) without committing to a full unified component.</p><p>ANATOMY tab reuses the same SVG schematic infrastructure shipped in May 2026 (the 9 spacecraft diagrams). Fleet entries point to <code>static/diagrams/fleet/{id}.svg</code> if available; tab no-ops if not authored. CREW tab is new — list of mission patches + crew portraits per flight, organised chronologically.</p><p>This locks into the V1 implementation strategy (no ADR needed; component-level decision).</p><hr><h3 id="oq-5-—-i18n-50-entries-×-14-locales-700-overlay-files-same-tiangong-rollout-strategy" tabindex="-1">OQ-5 — i18n: 50 entries × 14 locales = 700 overlay files. Same Tiangong rollout strategy? <a class="header-anchor" href="#oq-5-—-i18n-50-entries-×-14-locales-700-overlay-files-same-tiangong-rollout-strategy" aria-label="Permalink to &quot;OQ-5 — i18n: 50 entries × 14 locales = 700 overlay files. Same Tiangong rollout strategy?&quot;">​</a></h3><p>PRD-011 / Tiangong Explorer rolled out 5 entries × 14 locales = 70 overlay files via auto-translate (DeepL / Claude with human review) per ADR-017 / ADR-033. Fleet is 10× the volume.</p><table tabindex="0"><thead><tr><th>Option</th><th>Scope</th><th>Cost</th></tr></thead><tbody><tr><td><strong>A. en-US only at launch, rely on en-US fallback</strong> (per ADR-017 fallback)</td><td>50 files</td><td>Smallest scope; non-English users see English fleet content</td></tr><tr><td><strong>B. en-US + es</strong> (mirrors existing ADR-017 baseline locales)</td><td>100 files</td><td>2× scope; covers the existing two-locale baseline</td></tr><tr><td><strong>C. All 14 locales</strong> (matches Tiangong / ISS rollout)</td><td>700 files</td><td>14× scope; full i18n parity</td></tr></tbody></table><p><strong>Recommendation: B for V1 launch, C as a follow-up slice.</strong> Ship en-US + es locked-in; the Spanish translation pipeline is well-tested. The remaining 12 locales (de / fr / ja / it / ko / nl / pl / pt / ru / sv / tr / zh) follow in a v0.6.x slice after V1 ships, using the same auto-translate + spot-check pattern as Tiangong (ADR-033). This keeps the V1 surface tight while acknowledging the eventual full-locale parity goal.</p><p>This locks into ADR-054.</p><hr><h3 id="oq-6-—-filter-chip-taxonomy-which-axes" tabindex="-1">OQ-6 — Filter chip taxonomy: which axes? <a class="header-anchor" href="#oq-6-—-filter-chip-taxonomy-which-axes" aria-label="Permalink to &quot;OQ-6 — Filter chip taxonomy: which axes?&quot;">​</a></h3><p>PRD-012 §what-it-must-do specifies CATEGORY / AGENCY / ERA / STATUS chips. Concrete sets:</p><table tabindex="0"><thead><tr><th>Chip</th><th>Values</th></tr></thead><tbody><tr><td><strong>CATEGORY</strong></td><td>launcher / crewed-spacecraft / cargo-spacecraft / station / rover / lander / orbiter / observatory</td></tr><tr><td><strong>AGENCY</strong></td><td>NASA / Roscosmos / ESA / JAXA / CNSA / ISRO / SpaceX / Northrop Grumman / Boeing / multi (e.g., ISS)</td></tr><tr><td><strong>ERA</strong></td><td>1957–1969 (Sputnik–Apollo 11) / 1969–1981 (post-Apollo–Shuttle debut) / 1981–2011 (Shuttle era) / 2011–now (post-Shuttle modern era) / planned</td></tr><tr><td><strong>STATUS</strong></td><td>FLOWN / ACTIVE / RETIRED / PLANNED</td></tr></tbody></table><p>Era boundaries chosen by inflection points (first crewed orbital → first lunar landing → Shuttle debut → Shuttle retirement → modern crewed-commercial era). Not &quot;decades&quot;, because the decades-by-tens cuts cross meaningful technology shifts (Apollo straddles the 60s/70s boundary).</p><p><strong>Recommendation: ship as specified.</strong> No new ADR — these are app-level UX decisions encoded in <code>/fleet/+page.svelte</code>.</p><hr><h3 id="oq-7-—-where-does-fleet-sit-in-the-nav" tabindex="-1">OQ-7 — Where does Fleet sit in the nav? <a class="header-anchor" href="#oq-7-—-where-does-fleet-sit-in-the-nav" aria-label="Permalink to &quot;OQ-7 — Where does Fleet sit in the nav?&quot;">​</a></h3><p>PRD-012 proposes <code>... → MARS → FLEET → SCIENCE</code>. Final order:</p><p><code>EXPLORE → MISSIONS → PLAN → FLY → EARTH → MOON → MARS → ISS → TIANGONG → FLEET → SCIENCE</code></p><p>(Note: per recent commit <code>5833415</code>, ISS / TIANGONG moved to the last menu slots before SCIENCE; FLEET inserts between TIANGONG and SCIENCE so the inventory-style screens cluster: ISS → Tiangong → Fleet → Science.)</p><p><strong>Recommendation: insert between TIANGONG and SCIENCE.</strong> Both stations and Fleet are inventory-shaped pages (cards / detail panels); placing them adjacent groups the catalogue cluster cleanly, with SCIENCE remaining the educational tail.</p><p>This locks into ADR-052 alongside the schema decision.</p><hr><h3 id="oq-8-—-hero-image-strategy-for-the-card-grid" tabindex="-1">OQ-8 — Hero-image strategy for the card grid? <a class="header-anchor" href="#oq-8-—-hero-image-strategy-for-the-card-grid" aria-label="Permalink to &quot;OQ-8 — Hero-image strategy for the card grid?&quot;">​</a></h3><p>50 cards each need a hero photo. The existing <code>/missions</code> grid uses agency-first imagery via ADR-046; same pattern ports.</p><p><strong>Recommendation: reuse the existing pipeline.</strong> <code>static/images/fleet/{id}.jpg</code> resolved at build time via <code>scripts/fetch-assets.ts</code>. Per-image provenance row in <code>image-provenance.json</code> (ADR-047). No new ADR needed.</p><hr><h2 id="decision-criteria" tabindex="-1">Decision criteria <a class="header-anchor" href="#decision-criteria" aria-label="Permalink to &quot;Decision criteria&quot;">​</a></h2><p>We accept the resolution when:</p><ol><li><strong>Schema validates.</strong> <code>validate-data.ts</code> enforces <code>fleet/index.json</code> + per-entry shape; every <code>linked_missions</code> ID resolves to an existing mission; every fleet <code>id</code> referenced from <code>missions[*].launch_vehicle</code> exists in fleet.</li><li><strong>50 cards render.</strong> Card grid loads, filter chips work, deep-link <code>?id=saturn-v</code> opens the detail panel pre-selected.</li><li><strong>Cross-references both ways.</strong> Saturn V&#39;s MISSIONS tab lists the 13 Apollo + Skylab missions; clicking <em>Apollo 11</em> deep-links to <code>/missions?id=apollo11</code> cleanly.</li><li><strong>Crew tab renders for crewed-spacecraft entries</strong> with at least one mission patch + crew portrait per flight (≥10 entries, varying counts of flights each). Provenance complete in <code>image-provenance.json</code>.</li><li><strong>Anatomy tab no-ops gracefully</strong> for entries without an authored SVG (most launchers initially) — UI shows a single placeholder line, not a broken tab.</li><li><strong>i18n parity en-US + es at launch.</strong> Remaining 12 locales tracked in a follow-up issue, ships in a v0.6.x slice.</li><li><strong>Mobile-first.</strong> 375 px width renders without horizontal scroll; bottom-sheet detail panel works as expected.</li><li><strong><code>?view=list</code> fallback</strong> — same ADR-042 pattern. Card grid is plain DOM already, but the contract is consistent.</li><li><strong>Provenance complete.</strong> Every image, every external link recorded in <code>image-provenance.json</code> / link-provenance pipeline (ADR-047 / ADR-051). Fail-closed at build.</li></ol><hr><h2 id="closure-path" tabindex="-1">Closure path <a class="header-anchor" href="#closure-path" aria-label="Permalink to &quot;Closure path&quot;">​</a></h2><ul><li><strong>ADR-052</strong> — Fleet schema + cross-reference contract: <code>index.json</code> + per-entry files under <code>fleet/{category}/{id}.json</code>; <code>linked_missions</code> curated explicitly, validated against <code>missions/index.json</code> at build; nav slot between TIANGONG and SCIENCE.</li><li><strong>ADR-053</strong> — Mission badge + crew portrait sourcing: agency-first per ADR-046 (NASA Image Library / ESA / JAXA / Roscosmos archives), Wikimedia Commons for canonical patch artwork, graceful no-op on missing images.</li><li><strong>ADR-054</strong> — Fleet i18n: en-US + es at V1 launch; remaining 12 locales via the existing ADR-033 auto-translate pipeline in a v0.6.x slice.</li></ul><p>Bidirectional reverse-link rendering on <code>/missions</code> panels (OQ-2 option B), unified <code>EntityDetailPanel.svelte</code> refactor (OQ-4 option C), and full 14-locale rollout (OQ-5 option C) all deferred to v0.7+.</p><hr><p><em>Orrery · RFC-016 · v0.1 · Open. Update on closure with the ADR numbers landed.</em></p>',72)])])}const m=t(i,[["render",r]]);export{g as __pageData,m as default};
